        messageCount: 5,
        messageIds: ["msg-1", "msg-2", "msg-3", "msg-4", "msg-5"],
        messages: [
          { createdAt: new Date(), id: "msg-1", modelMessage: { role: "user", content: "1" } },
        ],
        startMessageId: "msg-1",
        summary: null,
      };
      expect(segment.createdAt).toBeInstanceOf(Date);
      expect(segment.endMessageId).toBe("msg-10");
      expect(segment.estimatedTokens).toBe(3000);
      expect(segment.id).toBe("segment-1");
      expect(segment.messageCount).toBe(5);
      expect(segment.startMessageId).toBe("msg-1");
      expect(segment.summary).toBeNull();
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - missing required fields
      const invalidSegment: PreparedCompactionSegment = {};
      expect(invalidSegment).toBeDefined();
    });

    it("should have correct types for each field", () => {
      expectTypeOf<PreparedCompactionSegment["createdAt"]>().toEqualTypeOf<Date>();
      expectTypeOf<PreparedCompactionSegment["endMessageId"]>().toEqualTypeOf<string>();
      expectTypeOf<PreparedCompactionSegment["estimatedTokens"]>().toEqualTypeOf<number>();
      expectTypeOf<PreparedCompactionSegment["id"]>().toEqualTypeOf<string>();
      expectTypeOf<PreparedCompactionSegment["messageCount"]>().toEqualTypeOf<number>();
      expectTypeOf<PreparedCompactionSegment["messageIds"]>().toEqualTypeOf<string[]>();
      expectTypeOf<PreparedCompactionSegment["messages"]>().toEqualTypeOf<Message[]>();
      expectTypeOf<PreparedCompactionSegment["startMessageId"]>().toEqualTypeOf<string>();
      expectTypeOf<PreparedCompactionSegment["summary"]>().toEqualTypeOf<CompactionSummary | null>();
    });
  });

  // ============================================
  // 21. PreparedCompaction Interface
  // ============================================
  describe("PreparedCompaction", () => {
    it("should have all required fields", () => {
      const compaction: PreparedCompaction = {
        actualUsage: null,
        baseMessageIds: ["msg-1", "msg-2"],
        baseRevision: 1,
        baseSegmentIds: ["segment-1"],
        compactionMaxTokensAtCreation: 8000,
        contextLimitAtCreation: 128000,
        didChange: false,
        keepRecentTokensAtCreation: 2000,
        pendingCompaction: false,
        phase: "new-turn",
        rejected: false,
        segments: [],
        tokenDelta: -3000,
      };
      expect(compaction.actualUsage).toBeNull();
      expect(compaction.baseMessageIds).toEqual(["msg-1", "msg-2"]);
      expect(compaction.baseRevision).toBe(1);
      expect(compaction.baseSegmentIds).toEqual(["segment-1"]);
      expect(compaction.compactionMaxTokensAtCreation).toBe(8000);
      expect(compaction.contextLimitAtCreation).toBe(128000);
      expect(compaction.didChange).toBe(false);
      expect(compaction.keepRecentTokensAtCreation).toBe(2000);
      expect(compaction.pendingCompaction).toBe(false);
      expect(compaction.phase).toBe("new-turn");
      expect(compaction.rejected).toBe(false);
      expect(compaction.segments).toEqual([]);
      expect(compaction.tokenDelta).toBe(-3000);
    });

    it("should accept actualUsage with ActualTokenUsage", () => {
      const usage: ActualTokenUsage = {
        completionTokens: 100,
        promptTokens: 50,
        totalTokens: 150,
        updatedAt: new Date(),
      };
      const compaction: PreparedCompaction = {
        actualUsage: usage,
        baseMessageIds: [],
        baseRevision: 1,
        baseSegmentIds: [],
        compactionMaxTokensAtCreation: 8000,
        contextLimitAtCreation: 128000,
        didChange: false,
        keepRecentTokensAtCreation: 2000,
        pendingCompaction: false,
        phase: "intermediate-step",
        rejected: false,
        segments: [],
        tokenDelta: 0,
      };
      expect(compaction.actualUsage).toBeDefined();
      expect(compaction.actualUsage?.totalTokens).toBe(150);
    });

    it("should accept both phase values", () => {
      const intermediateStep: PreparedCompaction = {
        actualUsage: null,
        baseMessageIds: [],
        baseRevision: 1,
        baseSegmentIds: [],
        compactionMaxTokensAtCreation: 8000,
        contextLimitAtCreation: 128000,
        didChange: false,
        keepRecentTokensAtCreation: 2000,
        pendingCompaction: false,
        phase: "intermediate-step",
        rejected: false,
        segments: [],
        tokenDelta: 0,
      };
      const newTurn: PreparedCompaction = {
        actualUsage: null,
        baseMessageIds: [],
        baseRevision: 1,
        baseSegmentIds: [],
        compactionMaxTokensAtCreation: 8000,
        contextLimitAtCreation: 128000,
        didChange: false,
        keepRecentTokensAtCreation: 2000,
        pendingCompaction: false,
        phase: "new-turn",
        rejected: false,
        segments: [],
        tokenDelta: 0,
      };
      expect(intermediateStep.phase).toBe("intermediate-step");
      expect(newTurn.phase).toBe("new-turn");
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - missing required fields
      const invalidCompaction: PreparedCompaction = {};
      expect(invalidCompaction).toBeDefined();
    });

    it("should have correct types for each field", () => {
      expectTypeOf<PreparedCompaction["actualUsage"]>().toEqualTypeOf<ActualTokenUsage | null>();
      expectTypeOf<PreparedCompaction["baseMessageIds"]>().toEqualTypeOf<string[]>();
      expectTypeOf<PreparedCompaction["baseRevision"]>().toEqualTypeOf<number>();
      expectTypeOf<PreparedCompaction["baseSegmentIds"]>().toEqualTypeOf<string[]>();
      expectTypeOf<PreparedCompaction["compactionMaxTokensAtCreation"]>().toEqualTypeOf<number>();
      expectTypeOf<PreparedCompaction["contextLimitAtCreation"]>().toEqualTypeOf<number>();
      expectTypeOf<PreparedCompaction["didChange"]>().toEqualTypeOf<boolean>();
      expectTypeOf<PreparedCompaction["keepRecentTokensAtCreation"]>().toEqualTypeOf<number>();
      expectTypeOf<PreparedCompaction["pendingCompaction"]>().toEqualTypeOf<boolean>();
      expectTypeOf<PreparedCompaction["phase"]>().toEqualTypeOf<"intermediate-step" | "new-turn">();
      expectTypeOf<PreparedCompaction["rejected"]>().toEqualTypeOf<boolean>();
      expectTypeOf<PreparedCompaction["segments"]>().toEqualTypeOf<PreparedCompactionSegment[]>();
      expectTypeOf<PreparedCompaction["tokenDelta"]>().toEqualTypeOf<number>();
    });
  });

  // ============================================
  // Type Compatibility Tests
  // ============================================
  describe("Type Compatibility", () => {
    it("Message should be compatible with CheckpointMessage for modelMessage", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" },
      };
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-123",
        isSummary: false,
        message: message.modelMessage,
      };
      expect(checkpoint.message).toBeDefined();
    });

    it("CompactionConfig should be compatible with partial updates", () => {
      const defaultConfig: CompactionConfig = {};
      const partialConfig: Partial<CompactionConfig> = defaultConfig;
      expect(partialConfig.enabled).toBeUndefined();
    });

    it("PreparedCompactionSegment should be assignable to CompactionSegment", () => {
      const prepared: PreparedCompactionSegment = {
        createdAt: new Date(),
        endMessageId: "msg-10",
        estimatedTokens: 3000,
        id: "segment-1",
        messageCount: 5,
        messageIds: ["msg-1"],
        messages: [],
        startMessageId: "msg-1",
        summary: null,
      };
      // Both have the same structure, should be compatible
      const segment: CompactionSegment = prepared;
      expect(segment.id).toBe("segment-1");
    });

    it("SessionFileLine union should discriminate by type field", () => {
      const headerLine: SessionFileLine = {
        createdAt: Date.now(),
        sessionId: "session-1",
        type: "header",
        version: 1,
      };
      const messageLine: SessionFileLine = {
        createdAt: Date.now(),
        id: "msg-1",
        isSummary: false,
        message: { role: "user", content: "test" },
        type: "message",
      };
      const checkpointLine: SessionFileLine = {
        summaryMessageId: "summary-1",
        type: "checkpoint",
        updatedAt: Date.now(),
      };

      expect(headerLine.type).toBe("header");
      expect(messageLine.type).toBe("message");
      expect(checkpointLine.type).toBe("checkpoint");
    });

    it("ActualTokenUsageInput should be assignable to ActualTokenUsage", () => {
      const input: ActualTokenUsageInput = {
        completionTokens: 100,
        promptTokens: 50,
        totalTokens: 150,
        updatedAt: new Date(),
      };
      // Input has all required fields for ActualTokenUsage
      const usage: ActualTokenUsage = {
        completionTokens: input.completionTokens ?? 0,
        promptTokens: input.promptTokens ?? 0,
        totalTokens: input.totalTokens ?? 0,
        updatedAt: input.updatedAt ?? new Date(),
      };
      expect(usage.totalTokens).toBe(150);
    });
  });
});

